68	    hasUnlimitedCanvases: true,
69	  },
70	};
71	
72	// A plan only grants Pro/Workspace features when the subscription is active or trialing.
73	const ACTIVE_STATUSES = new Set(["active", "trialing"]);
74	
75	export const useSubscription = (): SubscriptionState => {
76	  const [plan, setPlan] = useState<SubscriptionPlan>("free");
77	  const [status, setStatus] = useState("inactive");
78	  const [isLoading, setIsLoading] = useState(true);
79	  const [kiraActionsToday, setKiraActionsToday] = useState(0);
80	  const [kiraActionsLimit, setKiraActionsLimit] = useState(10);
81	  const [invoicesUsedThisMonth, setInvoicesUsedThisMonth] = useState(0);
82	  const [canvasesUsedThisMonth, setCanvasesUsedThisMonth] = useState(0);
83	
84	  const applyProfile = (profile: Record<string, unknown>) => {
85	    setPlan((profile.subscription_plan as SubscriptionPlan) || "free");
86	    setStatus((profile.subscription_status as string) || "inactive");
87	    setKiraActionsToday((profile.kira_actions_used as number) || 0);
88	    setKiraActionsLimit((profile.kira_actions_limit as number) || 10);
89	    setInvoicesUsedThisMonth((profile.invoices_used_this_month as number) || 0);
90	    setCanvasesUsedThisMonth((profile.canvases_used_this_month as number) || 0);
91	  };
92	
93	  useEffect(() => {
94	    let channel: ReturnType<typeof supabase.channel> | null = null;
95	
96	    const setup = async () => {
97	      const { data: { user } } = await supabase.auth.getUser();
98	      if (!user) {
99	        setIsLoading(false);
100	        return;
101	      }
102	
103	      const { data: profile } = await supabase
104	        .from("profiles")
105	        .select("subscription_plan, subscription_status, kira_actions_used, kira_actions_limit, invoices_used_this_month, canvases_used_this_month")
106	        .eq("id", user.id)
107	        .single();
108	
109	      if (profile) applyProfile(profile as Record<string, unknown>);
110	      setIsLoading(false);
111	
112	      // Real-time listener: fires the moment the Paystack webhook updates the profile row.
113	      channel = supabase
114	        .channel(`subscription:${user.id}`)
115	        .on(
116	          "postgres_changes",
117	          {
118	            event: "UPDATE",
119	            schema: "public",
120	            table: "profiles",
121	            filter: `id=eq.${user.id}`,
122	          },
123	          (payload) => {
124	            applyProfile(payload.new as Record<string, unknown>);
125	          }
126	        )
127	        .subscribe();
128	    };
129	
130	    setup();
131	
132	    return () => {
133	      if (channel) supabase.removeChannel(channel);
134	    };
135	  }, []);
136	
137	  const currentPlan = plan || "free";
138	  const limits = PLAN_LIMITS[currentPlan];
139	  const isActiveStatus = ACTIVE_STATUSES.has(status);
140	
141	  return {
142	    plan: currentPlan,
143	    status,
144	    isLoading,
145	    isPro: currentPlan === "creative_pro" && isActiveStatus,
146	    isBrandWorkspace: currentPlan === "brand_workspace" && isActiveStatus,
147	    isFree: currentPlan === "free" || !isActiveStatus,
148	    limits,
149	    kiraActionsToday,
150	    kiraActionsLimit,
151	    invoicesUsedThisMonth,
152	    canvasesUsedThisMonth,
153	  };
154	};

