-- ============================================================
-- Migration: Rename "contracts" to "canvases" throughout DB
-- ============================================================

-- 1. Rename table
ALTER TABLE public.contracts RENAME TO canvases;

-- 2. Rename profile columns
ALTER TABLE public.profiles RENAME COLUMN contracts_per_month TO canvases_per_month;
ALTER TABLE public.profiles RENAME COLUMN contracts_used_this_month TO canvases_used_this_month;

-- 3. Rename DB function
ALTER FUNCTION public.can_create_contract() RENAME TO can_create_canvas;

-- 4. Rename trigger (trigger now lives on the renamed table)
ALTER TRIGGER update_contracts_updated_at ON public.canvases RENAME TO update_canvases_updated_at;

-- 5. Rename RLS policies on the canvases table
-- Drop old policies and recreate with new names (same logic is preserved)

DROP POLICY IF EXISTS "Users can view own contracts" ON public.canvases;
CREATE POLICY "Users can view own canvases"
  ON public.canvases FOR SELECT
  USING (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users can create own contracts" ON public.canvases;
CREATE POLICY "Users can create own canvases"
  ON public.canvases FOR INSERT
  WITH CHECK (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users can update own contracts" ON public.canvases;
CREATE POLICY "Users can update own canvases"
  ON public.canvases FOR UPDATE
  USING (auth.uid() = user_id);

DROP POLICY IF EXISTS "Users can delete own contracts" ON public.canvases;
CREATE POLICY "Users can delete own canvases"
  ON public.canvases FOR DELETE
  USING (auth.uid() = user_id);

DROP POLICY IF EXISTS "Clients can view contracts addressed to them" ON public.canvases;
CREATE POLICY "Clients can view canvases addressed to them"
  ON public.canvases FOR SELECT
  USING (client_email = auth.jwt() ->> 'email');

-- 6. Rename constraint
ALTER TABLE public.canvases RENAME CONSTRAINT contracts_contract_type_check TO canvases_contract_type_check;

