  draft:   { label: "Draft",   color: "bg-gray-100 text-gray-600" },
  sent:    { label: "Sent",    color: "bg-blue-100 text-blue-700" },
  paid:    { label: "Paid",    color: "bg-emerald-100 text-emerald-700" },
  overdue: { label: "Overdue", color: "bg-red-100 text-red-700" },
};

const CONTRACT_STATUS: Record<string, { label: string; color: string }> = {
  draft:     { label: "Draft",     color: "bg-gray-100 text-gray-600" },
  sent:      { label: "Sent",      color: "bg-blue-100 text-blue-700" },
  signed:    { label: "Signed",    color: "bg-emerald-100 text-emerald-700" },
  active:    { label: "Active",    color: "bg-emerald-100 text-emerald-700" },
  completed: { label: "Completed", color: "bg-emerald-100 text-emerald-700" },
  cancelled: { label: "Cancelled", color: "bg-red-100 text-red-700" },
};

const ReceivedDocuments = () => {
  const [searchParams] = useSearchParams();
  const [invoices, setInvoices] = useState<any[]>([]);
  const [contracts, setContracts] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedInvoice, setSelectedInvoice] = useState<any>(null);
  const [selectedContract, setSelectedContract] = useState<any>(null);
  const [activeTab, setActiveTab] = useState(searchParams.get("tab") ?? "invoices");

  useEffect(() => {
    const load = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) { setLoading(false); return; }

      const email = session.user.email;
      if (!email) { setLoading(false); return; }

      const [{ data: inv }, { data: con }] = await Promise.all([
        supabase
          .from("invoices")
          .select("*")
          .eq("client_email", email)
          .order("created_at", { ascending: false }),
        supabase
          .from("canvases")
          .select("*")
          .eq("client_email", email)
          .order("created_at", { ascending: false }),
      ]);

      setInvoices(inv ?? []);
      setContracts(con ?? []);
      setLoading(false);

      const targetId = searchParams.get("id");
      if (targetId) {
        const matchContract = (con ?? []).find((c: any) => c.id === targetId);
        if (matchContract) { setSelectedContract(matchContract); return; }
        const matchInvoice = (inv ?? []).find((i: any) => i.id === targetId);
        if (matchInvoice) setSelectedInvoice(matchInvoice);
      }
    };
    load();
  }, []);

  const formatCurrency = (amount: number, currency = "KES") =>
    new Intl.NumberFormat("en-KE", { style: "currency", currency }).format(amount);

  if (loading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="w-8 h-8 rounded-full border-2 border-bronze border-t-transparent animate-spin" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <div className="border-b border-border/30">
        <div className="container mx-auto px-4 sm:px-6 py-8 max-w-4xl">
