                          <div className="w-9 h-9 rounded-lg bg-bronze/10 flex items-center justify-center flex-shrink-0">
                            <FileSignature className="h-4 w-4 text-bronze" />
                          </div>
                          <div className="min-w-0">
                            <p className="font-semibold text-sm truncate">{con.title}</p>
                            <p className="text-xs text-muted-foreground">
                              {format(new Date(con.created_at), "dd MMM yyyy")}
                            </p>
                          </div>
                        </div>
                        <span className={`text-[11px] font-semibold px-2 py-0.5 rounded-full flex-shrink-0 ${st.color}`}>
                          {st.label}
                        </span>
                      </div>
                    </Card>
                  );
                })}
              </div>
            )}
          </TabsContent>
        </Tabs>
      </div>

      {selectedInvoice && (
        <InvoicePreviewDialog
          open={!!selectedInvoice}
          onOpenChange={(v) => { if (!v) setSelectedInvoice(null); }}
          invoice={selectedInvoice}
        />
      )}
      {selectedContract && (
        <ContractPreviewDialog
          open={!!selectedContract}
          onOpenChange={(v) => { if (!v) setSelectedContract(null); }}
          contract={selectedContract}
          onContractUpdate={() => {}}
        />
      )}
    </div>
  );
};

export default ReceivedDocuments;

import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const ALLOWED_ORIGINS = [
  "https://crevia.app",
  "https://www.crevia.app",
  "http://localhost:8080",
  "http://localhost:5173",
  "https://creviamvp.vercel.app",
];

function getCorsHeaders(req: Request) {
  const origin = req.headers.get("Origin") ?? "";
  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
  return {
    "Access-Control-Allow-Origin": allowed,
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
    "Vary": "Origin",
  };
}

function formatCurrency(amount: number, currency: string): string {
  return new Intl.NumberFormat("en-KE", { style: "currency", currency }).format(amount);
}

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString("en-GB", {
    day: "2-digit", month: "short", year: "numeric",
  });
}

serve(async (req) => {
  const cors = getCorsHeaders(req);

  if (req.method === "OPTIONS") {
    return new Response(null, { headers: cors });
  }

  if (req.method !== "POST") {
    return new Response(JSON.stringify({ error: "Method not allowed" }), {
      status: 405, headers: { ...cors, "Content-Type": "application/json" },
    });
  }

  const authHeader = req.headers.get("Authorization");
  if (!authHeader?.startsWith("Bearer ")) {
    return new Response(JSON.stringify({ error: "Unauthorized" }), {
      status: 401, headers: { ...cors, "Content-Type": "application/json" },
    });
  }

  const resendKey = Deno.env.get("RESEND_API_KEY");
  if (!resendKey) {
    return new Response(JSON.stringify({ error: "Email service not configured" }), {
      status: 500, headers: { ...cors, "Content-Type": "application/json" },
    });
  }

  try {
    const { contract_id } = await req.json();
    if (!contract_id) {
      return new Response(JSON.stringify({ error: "contract_id required" }), {
        status: 400, headers: { ...cors, "Content-Type": "application/json" },
      });
    }

    // User-scoped client: anon key + caller's JWT so PostgREST uses auth.uid() for RLS
    const userClient = createClient(
      Deno.env.get("SUPABASE_URL")!,
      Deno.env.get("SUPABASE_ANON_KEY")!,
      { global: { headers: { Authorization: authHeader } } },
    );

    // Admin client: service role for writes that cross user boundaries
    const adminClient = createClient(
      Deno.env.get("SUPABASE_URL")!,
      Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!,
    );

    // Fetch contract as the authenticated user — RLS ensures they can only see their own
    const { data: contract, error: conErr } = await userClient
      .from("canvases")
      .select("*")
      .eq("id", contract_id)
      .single();

    if (conErr || !contract) {
      return new Response(JSON.stringify({ error: "Canvas not found" }), {
        status: 404, headers: { ...cors, "Content-Type": "application/json" },
      });
    }

    if (!contract.client_email) {
      return new Response(JSON.stringify({ error: "No client email on this Canvas" }), {
        status: 400, headers: { ...cors, "Content-Type": "application/json" },
      });
    }

    // Fetch sender profile + business settings
    const [{ data: profile }, { data: biz }] = await Promise.all([
      userClient.from("profiles").select("display_name, email").single(),
      userClient.from("business_settings").select("*").maybeSingle(),
    ]);

    const senderName = biz?.business_name || profile?.display_name || "Crevia User";
    const senderEmail = biz?.business_email || profile?.email || "";
    const currency = contract.currency || "KES";

    const deliverablesHtml = Array.isArray(contract.deliverables) && contract.deliverables.length
      ? `<ul style="margin:8px 0 0;padding-left:20px;">${contract.deliverables.map((d: string) =>
          `<li style="font-size:13px;color:#444;margin-bottom:4px;">${d}</li>`
        ).join("")}</ul>`
      : "";

    const html = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Canvas: ${contract.title}</title>
</head>
<body style="margin:0;padding:0;background:#f5f4f0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f5f4f0;padding:40px 16px;">
    <tr>
      <td align="center">
        <table width="100%" cellpadding="0" cellspacing="0" style="max-width:580px;background:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);">

          <!-- Header -->
          <tr>
            <td style="background:#1a1a1a;padding:28px 40px;">
              <table width="100%"><tr>
                <td>
                  <table cellpadding="0" cellspacing="0"><tr>
                    <td style="vertical-align:middle;padding-right:10px;">
                      <img src="https://creviamvp.vercel.app/crevia-logo.png" alt="Crevia" width="40" height="40" style="display:block;border-radius:50%;border:1px solid #333;" />
                    </td>
                    <td style="vertical-align:middle;">
                      <span style="font-size:22px;font-weight:700;color:#c9a96e;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;">Crevia</span>
                    </td>
                  </tr></table>
                </td>
                <td align="right">
                  <p style="margin:0;font-size:13px;color:#888;">Canvas</p>
                  <p style="margin:2px 0 0;font-size:16px;font-weight:700;color:#fff;">${contract.title}</p>
                </td>
              </tr></table>
            </td>
          </tr>

          <!-- Parties -->
          <tr>
            <td style="padding:28px 40px 0;">
              <table width="100%"><tr>
                <td style="vertical-align:top;">
                  <p style="margin:0 0 2px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">From</p>
                  <p style="margin:0;font-size:14px;font-weight:600;color:#111;">${senderName}</p>
                  ${senderEmail ? `<p style="margin:2px 0 0;font-size:13px;color:#666;">${senderEmail}</p>` : ""}
                </td>
                <td style="vertical-align:top;" align="right">
                  <p style="margin:0 0 2px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">To</p>
                  <p style="margin:0;font-size:14px;font-weight:600;color:#111;">${contract.client_name}</p>
                  <p style="margin:2px 0 0;font-size:13px;color:#666;">${contract.client_email}</p>
                </td>
              </tr></table>
            </td>
          </tr>

          <!-- Key Terms -->
          <tr>
            <td style="padding:20px 40px 0;">
              <table width="100%" cellpadding="0" cellspacing="0">
                <tr>
                  <td style="background:#f9f7f3;border-radius:8px;padding:16px 20px;">
                    <table width="100%">
                      <tr>
                        ${contract.start_date ? `<td>
                          <p style="margin:0 0 2px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">Start Date</p>
                          <p style="margin:0;font-size:14px;font-weight:500;color:#333;">${formatDate(contract.start_date)}</p>
                        </td>` : ""}
                        ${contract.end_date ? `<td align="center">
                          <p style="margin:0 0 2px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">End Date</p>
                          <p style="margin:0;font-size:14px;font-weight:600;color:#c9a96e;">${formatDate(contract.end_date)}</p>
                        </td>` : ""}
                        ${contract.value ? `<td align="right">
                          <p style="margin:0 0 2px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">Canvas Value</p>
                          <p style="margin:0;font-size:18px;font-weight:700;color:#111;">${formatCurrency(contract.value, currency)}</p>
                        </td>` : ""}
                      </tr>
                    </table>
                  </td>
                </tr>
              </table>
            </td>
          </tr>

          <!-- Deliverables -->
          ${deliverablesHtml ? `
          <tr>
            <td style="padding:20px 40px 0;">
              <p style="margin:0 0 6px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">Deliverables</p>
              ${deliverablesHtml}
            </td>
          </tr>` : ""}

          <!-- Payment Terms -->
          ${contract.payment_terms ? `
          <tr>
            <td style="padding:16px 40px 0;">
              <p style="margin:0 0 6px;font-size:11px;color:#aaa;text-transform:uppercase;letter-spacing:0.7px;">Payment Terms</p>
              <p style="margin:0;font-size:13px;color:#444;line-height:1.6;">${contract.payment_terms}</p>
            </td>
          </tr>` : ""}

          <!-- CTA -->
          <tr>
            <td style="padding:28px 40px;">
              <table width="100%"><tr><td align="center">
                <a href="https://creviamvp.vercel.app/received?tab=canvases&id=${contract_id}" style="display:inline-block;background:#c9a96e;color:#fff;text-decoration:none;padding:14px 32px;border-radius:8px;font-weight:700;font-size:15px;">
                  View &amp; Sign Canvas
                </a>
              </td></tr></table>
            </td>
          </tr>

          <!-- Footer -->
          <tr>
            <td style="padding:0 40px 32px;border-top:1px solid #f0ede8;">
              <p style="margin:16px 0 0;font-size:12px;color:#aaa;line-height:1.7;">
                This Canvas was sent via <strong style="color:#c9a96e;">Crevia</strong> · creviamvp.vercel.app<br/>
                Log in to your Crevia account to review and sign.
              </p>
            </td>
          </tr>

        </table>
      </td>
    </tr>
  </table>
</body>
</html>`;

    // Send email via Resend
    const emailRes = await fetch("https://api.resend.com/emails", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${resendKey}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        from: `${senderName} via Crevia <contracts@crevia.app>`,
        to: contract.client_email,
        reply_to: senderEmail || undefined,
        subject: `Canvas from ${senderName}: ${contract.title}`,
        html,
      }),
    });

    if (!emailRes.ok) {
      const errBody = await emailRes.text();
      console.error("Resend error:", errBody);
      let resendMsg = "Failed to send email";
      try { resendMsg = JSON.parse(errBody)?.message || resendMsg; } catch {}
      return new Response(JSON.stringify({ error: resendMsg }), {
        status: 500, headers: { ...cors, "Content-Type": "application/json" },
      });
    }

    // Mark contract as sent
    await adminClient
      .from("canvases")
      .update({ status: "sent" })
      .eq("id", contract_id);

    // Notify client if they have a Crevia account
    const { data: clientProfile } = await adminClient
      .from("profiles")
      .select("id")
      .eq("email", contract.client_email)
      .maybeSingle();

    if (clientProfile?.id) {
      await adminClient.from("notifications").insert({
        user_id: clientProfile.id,
        type: "canvas_received",
        title: `Canvas from ${senderName}`,
        body: `You have received a Canvas: "${contract.title}". Review and sign it on Crevia.`,
        data: { contract_id, link: "/received" },
      });
    }

    return new Response(JSON.stringify({ sent: true }), {
      status: 200, headers: { ...cors, "Content-Type": "application/json" },
    });

  } catch (err) {
    console.error("contract-send error:", err);
    return new Response(JSON.stringify({ error: "Internal server error" }), {
      status: 500, headers: { ...cors, "Content-Type": "application/json" },
    });
  }
});

import { useState, useEffect, useCallback } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Send, Receipt, FileSignature, Mail, MessageSquare, Search, Users, User } from "lucide-react";
import { toast } from "sonner";
import { cn } from "@/lib/utils";

interface SendDocumentDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  type: "invoice" | "contract";
  documentId: string;
  defaultEmail: string;
  documentLabel: string;
  onSent?: () => void;
}

interface Room {
  id: string;
  name: string | null;
  is_group: boolean;
  dmPartnerName?: string | null;
  dmPartnerAvatar?: string | null;
}

type SendMethod = "email" | "workspace";

export function SendDocumentDialog({
  open,
  onOpenChange,
  type,
  documentId,
  defaultEmail,
  documentLabel,
  onSent,
}: SendDocumentDialogProps) {
  const [sendMethod, setSendMethod] = useState<SendMethod>("email");

  // Email state
  const [email, setEmail] = useState(defaultEmail);
  const [note, setNote] = useState("");
  const [sending, setSending] = useState(false);

  // Workspace DM state
  const [userId, setUserId] = useState("");
  const [rooms, setRooms] = useState<Room[]>([]);
  const [roomsLoading, setRoomsLoading] = useState(false);
  const [roomSearch, setRoomSearch] = useState("");
  const [selectedRoom, setSelectedRoom] = useState<Room | null>(null);
  const [dmSending, setDmSending] = useState(false);

  const Icon = type === "invoice" ? Receipt : FileSignature;
  const fnName = type === "invoice" ? "invoice-send" : "canvas-send";
  const bodyKey = type === "invoice" ? "invoice_id" : "contract_id";

  // Reset on open/close
  useEffect(() => {
    if (open) {
      setEmail(defaultEmail);
      setNote("");
      setSendMethod("email");
      setSelectedRoom(null);
      setRoomSearch("");
    }
  }, [open, defaultEmail]);

  // Fetch current user
  useEffect(() => {
    if (!open) return;
    supabase.auth.getUser().then(({ data: { user } }) => {
      if (user) setUserId(user.id);
    });
  }, [open]);

  // Fetch rooms when workspace tab is active
  const fetchRooms = useCallback(async () => {
    if (!userId) return;
    setRoomsLoading(true);

    const { data: memberRooms } = await supabase
      .from("chat_room_members")
      .select("room_id")
      .eq("user_id", userId);

    if (!memberRooms?.length) {
      setRoomsLoading(false);
      return;
    }

    const roomIds = memberRooms.map((m) => m.room_id);
    const { data: roomsData } = await supabase
      .from("chat_rooms")
      .select("id, name, is_group, chat_room_members(user_id)")
      .in("id", roomIds)
      .order("updated_at", { ascending: false });

    if (!roomsData) {
      setRoomsLoading(false);
      return;
    }

    const enriched: Room[] = await Promise.all(
      roomsData.map(async (r) => {
        const memberIds: string[] = (r.chat_room_members ?? []).map(
          (m: { user_id: string }) => m.user_id
        );
        if (r.name === null && !r.is_group) {
          const partnerId = memberIds.find((id) => id !== userId);
          if (partnerId) {
            const { data: profile } = await supabase
              .from("profiles")
              .select("display_name, handle, avatar_url")
              .eq("id", partnerId)
              .single();
            if (profile) {
              return {
                id: r.id,
                name: null,
                is_group: false,
                dmPartnerName: profile.display_name || (profile.handle ? `@${profile.handle}` : null),
                dmPartnerAvatar: profile.avatar_url,
              };
            }
          }
        }
        return { id: r.id, name: r.name, is_group: r.is_group };
      })
    );

    setRooms(enriched);
    setRoomsLoading(false);
  }, [userId]);

  useEffect(() => {
    if (sendMethod === "workspace" && userId && rooms.length === 0) {
      fetchRooms();
    }
  }, [sendMethod, userId, rooms.length, fetchRooms]);

  const handleEmailSend = async () => {
    const trimmed = email.trim();
    if (!trimmed || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(trimmed)) {
      toast.error("Enter a valid email address");
      return;
    }

    setSending(true);
    try {
      if (trimmed !== defaultEmail) {
        const table = type === "invoice" ? "invoices" : "canvases";
        await supabase.from(table).update({ client_email: trimmed }).eq("id", documentId);
      }

      const { error, data } = await supabase.functions.invoke(fnName, {
        body: { [bodyKey]: documentId, note: note.trim() || undefined },
      });

      if (error) {
        let msg = error.message;
        try {
          const body = await (error as any).context?.json?.();
          if (body?.error) msg = body.error;
        } catch {}
        throw new Error(msg);
      }
      if (data?.error) throw new Error(data.error);

      toast.success(`${type === "invoice" ? "Invoice" : "Canvas"} sent!`, {
        description: `Sent to ${trimmed}. They'll receive an email and an in-app notification if they have a Crevia account.`,
      });
      onSent?.();
      onOpenChange(false);
    } catch (err: any) {
      toast.error("Failed to send", { description: err.message });
    } finally {
      setSending(false);
    }
  };

  const handleDmSend = async () => {
    if (!selectedRoom || !userId) {
      toast.error("Select a workspace or DM first");
      return;
    }

    setDmSending(true);
    try {
      const label = type === "invoice" ? "Invoice" : "Canvas";
      const content = type === "invoice"
        ? `📄 Sent ${label}: ${documentLabel}`
        : `📋 Sent ${label}: ${documentLabel}`;

      const msgPayload: Record<string, unknown> = {
        room_id: selectedRoom.id,
        sender_id: userId,
        content,
        message_type: type,
        is_encrypted: false,
      };
      if (type === "invoice") msgPayload.invoice_id = documentId;
      else msgPayload.contract_id = documentId;

      const { error } = await supabase.from("chat_messages").insert(msgPayload);
      if (error) throw error;

      await supabase
        .from("chat_rooms")
        .update({ updated_at: new Date().toISOString() })
        .eq("id", selectedRoom.id);

      const roomLabel = selectedRoom.name ?? selectedRoom.dmPartnerName ?? "the workspace";
      toast.success(`${label} shared!`, { description: `Sent to ${roomLabel}.` });
      onSent?.();
      onOpenChange(false);
    } catch (err: any) {
      toast.error("Failed to share", { description: err.message });
    } finally {
      setDmSending(false);
    }
  };

  const filteredRooms = rooms.filter((r) => {
    const q = roomSearch.toLowerCase();
    if (!q) return true;
    const label = r.name ?? r.dmPartnerName ?? "";
    return label.toLowerCase().includes(q);
  });

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <div className="flex items-center gap-2 mb-1">
            <div className="w-8 h-8 rounded-lg bg-bronze/10 flex items-center justify-center">
              <Icon className="w-4 h-4 text-bronze" />
            </div>
            <DialogTitle className="font-vollkorn text-lg">
              Send {type === "invoice" ? "Invoice" : "Canvas"}
            </DialogTitle>
          </div>
          <DialogDescription className="text-sm text-muted-foreground">
            {documentLabel}
          </DialogDescription>
        </DialogHeader>

        {/* Method toggle */}
        <div className="flex gap-1 p-1 bg-muted/50 rounded-xl border border-border/40">
          <button
            type="button"
            onClick={() => setSendMethod("email")}
            className={cn(
              "flex-1 flex items-center justify-center gap-1.5 py-2 rounded-lg text-xs font-semibold transition-all duration-150",
              sendMethod === "email"
                ? "bg-background text-foreground shadow-sm border border-border/60"
                : "text-muted-foreground hover:text-foreground"
            )}
          >
            <Mail className="w-3.5 h-3.5" />
            Email
          </button>
          <button
            type="button"
            onClick={() => setSendMethod("workspace")}
            className={cn(
              "flex-1 flex items-center justify-center gap-1.5 py-2 rounded-lg text-xs font-semibold transition-all duration-150",
              sendMethod === "workspace"
                ? "bg-background text-foreground shadow-sm border border-border/60"
                : "text-muted-foreground hover:text-foreground"
            )}
          >
            <MessageSquare className="w-3.5 h-3.5" />
            Workspace DM
          </button>
        </div>

        {sendMethod === "email" ? (
          <div className="space-y-4 pt-1">
            <div className="space-y-1.5">
              <Label htmlFor="send-email" className="text-sm font-medium">
                Recipient email
              </Label>
              <Input
                id="send-email"
                type="email"
                placeholder="client@example.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="h-10"
                autoFocus
              />
              <p className="text-[11px] text-muted-foreground">
                They'll receive a full copy by email. If they have a Crevia account, they'll also get an in-app notification and can view it under <strong>Received</strong>.
              </p>
            </div>

            <div className="space-y-1.5">
              <Label htmlFor="send-note" className="text-sm font-medium">
                Personal note <span className="text-muted-foreground font-normal">(optional)</span>
              </Label>
              <Textarea
                id="send-note"
                placeholder="Hi — please find the attached invoice. Let me know if you have any questions."
                value={note}
                onChange={(e) => setNote(e.target.value)}
                className="resize-none h-20 text-sm"
              />
            </div>

            <div className="flex gap-2 pt-1">
              <Button
                variant="outline"
                className="flex-1"
                onClick={() => onOpenChange(false)}
                disabled={sending}
              >
                Cancel
              </Button>
              <Button
                className="flex-1 bg-bronze hover:bg-bronze-dark text-white gap-1.5"
                onClick={handleEmailSend}
                disabled={sending}
              >
                <Send className="w-3.5 h-3.5" />
                {sending ? "Sending…" : "Send"}
              </Button>
            </div>
          </div>
        ) : (
          <div className="space-y-3 pt-1">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-muted-foreground pointer-events-none" />
              <Input
                placeholder="Search workspaces & DMs…"
                value={roomSearch}
                onChange={(e) => setRoomSearch(e.target.value)}
                className="pl-9 h-9 text-sm"
              />
            </div>

            <div className="border border-border/50 rounded-xl overflow-hidden max-h-52 overflow-y-auto">
              {roomsLoading ? (
                <div className="flex items-center justify-center py-8 text-sm text-muted-foreground">
                  Loading…
                </div>
              ) : filteredRooms.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-8 gap-1 text-sm text-muted-foreground">
                  <MessageSquare className="w-8 h-8 opacity-30 mb-1" />
                  {rooms.length === 0 ? "No workspaces or DMs yet" : "No matches"}
                </div>
              ) : (
                filteredRooms.map((room) => {
                  const isSelected = selectedRoom?.id === room.id;
                  const label = room.name ?? room.dmPartnerName ?? "Unknown";
                  const isWorkspace = room.is_group || room.name !== null;
                  return (
                    <button
                      key={room.id}
                      type="button"
                      onClick={() => setSelectedRoom(room)}
                      className={cn(
                        "w-full flex items-center gap-3 px-4 py-3 text-left transition-colors",
                        "border-b border-border/30 last:border-b-0",
                        isSelected
                          ? "bg-bronze/10 text-bronze"
                          : "hover:bg-muted/60 text-foreground"
                      )}
                    >
                      <div className={cn(
                        "w-7 h-7 rounded-full flex items-center justify-center flex-shrink-0 text-xs font-bold",
                        isSelected ? "bg-bronze/20 text-bronze" : "bg-muted text-muted-foreground"
                      )}>
                        {isWorkspace
                          ? <Users className="w-3.5 h-3.5" />
                          : room.dmPartnerAvatar
                            ? <img src={room.dmPartnerAvatar} className="w-7 h-7 rounded-full object-cover" alt="" />
                            : <User className="w-3.5 h-3.5" />
                        }
                      </div>
                      <div className="min-w-0">
                        <p className="text-sm font-medium truncate">{label}</p>
                        <p className="text-[11px] text-muted-foreground">
                          {isWorkspace ? "Workspace" : "Direct message"}
                        </p>
                      </div>
                      {isSelected && (
                        <div className="ml-auto w-2 h-2 rounded-full bg-bronze flex-shrink-0" />
                      )}
                    </button>
                  );
                })
              )}
            </div>

            <div className="flex gap-2 pt-1">
              <Button
                variant="outline"
                className="flex-1"
                onClick={() => onOpenChange(false)}
                disabled={dmSending}
              >
                Cancel
              </Button>
              <Button
                className="flex-1 bg-bronze hover:bg-bronze-dark text-white gap-1.5"
                onClick={handleDmSend}
                disabled={dmSending || !selectedRoom}
              >
                <Send className="w-3.5 h-3.5" />
                {dmSending ? "Sending…" : "Share"}
              </Button>
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

