1119	                <p className="text-[10px] text-white/30 uppercase tracking-wider font-semibold mb-2">Included features</p>
1120	                <ul className="space-y-1.5">
1121	                  {plan.features.map(f => (
1122	                    <li key={f} className="flex items-center gap-2 text-xs text-white/50">
1123	                      <span className={cn("w-1.5 h-1.5 rounded-full flex-shrink-0", plan.key === "pro" ? "bg-emerald-500" : "bg-violet-500")} />
1124	                      {f}
