1	import { useState, useEffect, useRef } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import {
4	  Dialog,
5	  DialogContent,
6	  DialogHeader,
7	  DialogTitle,
8	} from "@/components/ui/dialog";
9	import { Input } from "@/components/ui/input";
10	import { Button } from "@/components/ui/button";
11	import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
12	import { Badge } from "@/components/ui/badge";
13	import { toast } from "sonner";
14	import { Users, Search, UserPlus, X, Loader2, Crown, Link2, Copy, Check, ShieldCheck, ShieldOff } from "lucide-react";
15	
16	interface Member {
17	  user_id: string;
18	  role: string;
19	  profile: {
20	    display_name: string | null;
21	    email: string | null;
22	    avatar_url: string | null;
23	  };
24	}
25	
26	interface SearchResult {
27	  id: string;
28	  display_name: string | null;
29	  email: string | null;
30	  avatar_url: string | null;
31	}
32	
33	interface Props {
34	  open: boolean;
35	  onOpenChange: (open: boolean) => void;
36	  roomId: string;
37	  createdBy: string;
38	  currentUserId: string;
39	}
40	
41	const WorkspaceMembersDialog = ({ open, onOpenChange, roomId, createdBy, currentUserId }: Props) => {
42	  const [members, setMembers] = useState<Member[]>([]);
43	  const [loadingMembers, setLoadingMembers] = useState(true);
44	  const [search, setSearch] = useState("");
45	  const [searchResults, setSearchResults] = useState<SearchResult[]>([]);
46	  const [searching, setSearching] = useState(false);
47	  const [addingId, setAddingId] = useState<string | null>(null);
48	  const [removingId, setRemovingId] = useState<string | null>(null);
49	  const [promotingId, setPromotingId] = useState<string | null>(null);
50	  const [generatingLink, setGeneratingLink] = useState(false);
51	  const [copiedLink, setCopiedLink] = useState(false);
52	  const searchTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
53	  const isCreator = currentUserId === createdBy;
54	
55	  useEffect(() => {
56	    if (open) {
57	      fetchMembers();
58	      setSearch("");
59	      setSearchResults([]);
60	    }
61	  }, [open, roomId]);
62	
63	  const fetchMembers = async () => {
64	    setLoadingMembers(true);
65	    const { data } = await supabase
66	      .from("chat_room_members")
67	      .select("user_id, role")
68	      .eq("room_id", roomId);
69	
70	    if (!data) { setLoadingMembers(false); return; }
71	
72	    const profileIds = data.map((m) => m.user_id);
73	    const { data: profiles } = await supabase
74	      .from("profiles")
75	      .select("id, display_name, email, avatar_url")
76	      .in("id", profileIds);
77	
78	    const profileMap = Object.fromEntries((profiles || []).map((p) => [p.id, p]));
79	    setMembers(
80	      data.map((m) => ({
81	        user_id: m.user_id,
82	        role: m.role,
83	        profile: profileMap[m.user_id] || { display_name: null, email: null, avatar_url: null },
84	      }))
85	    );
86	    setLoadingMembers(false);
87	  };
88	
89	  const handleSearchChange = (value: string) => {
90	    setSearch(value);
91	    if (searchTimer.current) clearTimeout(searchTimer.current);
92	    if (!value.trim()) { setSearchResults([]); return; }
93	
94	    searchTimer.current = setTimeout(async () => {
95	      setSearching(true);
96	      const excludeIds = [currentUserId, ...members.map((m) => m.user_id)];
97	      let query = supabase
98	        .from("profiles")
99	        .select("id, display_name, email, avatar_url")
100	        .or(`email.ilike.%${value}%,display_name.ilike.%${value}%`)
101	        .limit(6);
102	
103	      if (excludeIds.length > 0) {
104	        query = query.not("id", "in", `(${excludeIds.join(",")})`);
105	      }
106	
107	      const { data } = await query;
108	      setSearchResults(data || []);
109	      setSearching(false);
110	    }, 300);
111	  };
112	
113	  const addMember = async (user: SearchResult) => {
114	    setAddingId(user.id);
115	    const { error } = await supabase
116	      .from("chat_room_members")
117	      .insert({ room_id: roomId, user_id: user.id, role: "member" });
118	
119	    if (error) {
120	      toast.error("Failed to add member");
121	    } else {
122	      toast.success(`${user.display_name || user.email} added to workspace`);
123	      setSearchResults((prev) => prev.filter((r) => r.id !== user.id));
124	      setSearch("");
125	      fetchMembers();
126	    }
127	    setAddingId(null);
128	  };
129	
130	  const removeMember = async (userId: string) => {
131	    setRemovingId(userId);
132	    const { error } = await supabase
133	      .from("chat_room_members")
134	      .delete()
135	      .eq("room_id", roomId)
136	      .eq("user_id", userId);
137	
138	    if (error) {
139	      toast.error("Failed to remove member");
140	    } else {
141	      setMembers((prev) => prev.filter((m) => m.user_id !== userId));
142	      toast.success("Member removed");
143	    }
144	    setRemovingId(null);
