import { useState, useEffect } from "react";
import SuccessOverlay from "@/components/ui/SuccessOverlay";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { FileSignature } from "lucide-react";
import { toast } from "sonner";

export interface ApplicationContext {
  campaignTitle: string;
  creatorName: string;
  creatorEmail: string | null;
  proposedPrice: number;
  deliverables: string[];
}

interface CreateContractDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  editingContract?: any;
  onSuccess: () => void;
  onCreated?: (id: string) => void;
  kiraContext?: Record<string, unknown> | null;
  applicationContext?: ApplicationContext | null;
}

const buildTemplate = (ctx: ApplicationContext): string => {
  const today = new Date().toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" });
  const price = Number(ctx.proposedPrice || 0).toLocaleString();
  const half = (Number(ctx.proposedPrice || 0) / 2).toLocaleString();
  const deliverableLines = ctx.deliverables?.length
    ? ctx.deliverables.map(d => `  • ${d}`).join("\n")
    : "  • As agreed between parties";
  return `CANVAS AGREEMENT
Campaign: ${ctx.campaignTitle}
Date: ${today}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

PARTIES
Brand (Client):  [Your Brand / Company Name]
Creator:         ${ctx.creatorName}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

DELIVERABLES
${deliverableLines}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

COMPENSATION
Total:                    KES ${price}
  Phase 1 (on start):     KES ${half}
  Phase 2 (on delivery):  KES ${half}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

TERMS & CONDITIONS

1. SCOPE OF WORK
   The Creator agrees to deliver the content described above in accordance
   with the campaign brief.

2. CONTENT RIGHTS
   Upon full payment, the Brand receives a non-exclusive licence to use
   the content across agreed platforms for the campaign duration.

3. TIMELINE
   Deliverables shall be submitted within a timeframe agreed by both parties.

4. REVISIONS
   The Creator will provide up to [2] rounds of revisions upon request.

5. CONFIDENTIALITY
   Both parties agree to keep the terms of this agreement confidential.

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

SIGNATURES

Brand (Client)
Signature: ________________________________
Name:      ________________________________
Date:      ________________________________

Creator
Signature: ________________________________
Name:      ${ctx.creatorName}
Date:      ________________________________
`;
};

const CreateContractDialog = ({
  open,
  onOpenChange,
  editingContract,
  onSuccess,
  onCreated,
  kiraContext,
  applicationContext,
}: CreateContractDialogProps) => {
  const [loading, setLoading] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [content, setContent] = useState("");

  useEffect(() => {
    if (!open) return;
    if (editingContract) {
      setContent(editingContract.content ?? "");
    } else if (applicationContext) {
      setContent(buildTemplate(applicationContext));
    } else if (kiraContext) {
      if (kiraContext.content) setContent(kiraContext.content as string);
    } else {
      setContent("");
    }
  }, [editingContract, kiraContext, applicationContext, open]);

  const handleSubmit = async () => {
    setLoading(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) { toast.error("Please log in"); return; }

      const autoTitle = applicationContext
        ? `Canvas – ${applicationContext.campaignTitle}`
        : `Canvas – ${new Date().toLocaleDateString()}`;
      const contractData = {
        user_id: session.user.id,
        title: editingContract?.title?.trim() || autoTitle,
        client_name: applicationContext?.creatorName || editingContract?.client_name?.trim() || "",
        client_email: applicationContext?.creatorEmail || editingContract?.client_email?.trim() || null,
        value: applicationContext?.proposedPrice || null,
        deliverables: applicationContext?.deliverables?.length ? applicationContext.deliverables : null,
        contract_type: "custom",
        content: content || null,
      };

      if (editingContract) {
        const { error } = await supabase
          .from("canvases")
          .update(contractData)
          .eq("id", editingContract.id);
        if (error) throw error;
        onSuccess();
        onOpenChange(false);
        toast.success("Canvas updated");
      } else {
        const { data: created, error } = await supabase
          .from("canvases")
          .insert(contractData)
          .select("id")
          .single();
        if (error) throw error;
        if (created?.id) onCreated?.(created.id);
        onOpenChange(false);
        setShowSuccess(true);
      }
    } catch (error: any) {
      if (error.message?.includes("contract_limit_reached")) {
        toast.error("Monthly limit reached", {
          description: "Free plan allows 2 Canvas per month. Upgrade to Pro for unlimited.",
        });
      } else {
        toast.error(error.message || "Failed to save Canvas");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <SuccessOverlay
        show={showSuccess}
        title="Canvas Created"
        subtitle="Your Canvas is ready to sign"
        onComplete={() => { setShowSuccess(false); onSuccess(); }}
      />

      <Dialog open={open} onOpenChange={onOpenChange}>
        <DialogContent className="w-[calc(100vw-16px)] sm:max-w-2xl lg:max-w-3xl max-h-[90vh] overflow-hidden flex flex-col p-0 gap-0 rounded-2xl">
          {/* Header */}
          <div className="px-4 sm:px-6 pt-5 pb-4 border-b border-border/50 flex-shrink-0">
            <DialogHeader>
              <DialogTitle className="font-vollkorn text-xl flex items-center gap-2">
                <div className="w-8 h-8 rounded-xl bg-primary/10 flex items-center justify-center">
                  <FileSignature className="h-4 w-4 text-primary" />
                </div>
                {editingContract ? "Edit Canvas" : applicationContext ? `Canvas – ${applicationContext.campaignTitle}` : "New Canvas"}
              </DialogTitle>
            </DialogHeader>
          </div>

          {/* Canvas */}
          <div className="flex-1 overflow-y-auto px-4 sm:px-6 py-4 sm:py-5">
            <Textarea
              value={content}
              onChange={(e) => setContent(e.target.value)}
              placeholder="Start writing your Canvas here…"
              className="rounded-xl font-mono text-sm leading-relaxed min-h-[520px] resize-none bg-background border-border/60 focus:border-primary/30 focus-visible:ring-primary/20"
              spellCheck={false}
              autoFocus
            />
          </div>

          {/* Footer */}
          <div className="px-4 sm:px-6 py-4 border-t border-border/50 flex items-center justify-between bg-muted/20 flex-shrink-0">
            <Button variant="ghost" onClick={() => onOpenChange(false)} className="rounded-xl">
              Cancel
            </Button>
            <Button
              onClick={handleSubmit}
              disabled={loading}
              className="rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/20"
            >
              {loading ? "Saving…" : editingContract ? "Update Canvas" : "Save Canvas"}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
};

export default CreateContractDialog;

import { useState, useEffect, useRef } from "react";
import { supabase } from "@/integrations/supabase/client";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import { Users, Search, UserPlus, X, Loader2, Crown, Link2, Copy, Check, ShieldCheck, ShieldOff, Lock } from "lucide-react";

const getSeatLimit = (plan: string | null): number => {
  if (plan === "business" || plan === "brand_workspace") return 3;
  if (plan === "enterprise") return 100;
  return 1; // free, pro, creative_pro
};

interface Member {
  user_id: string;
  role: string;
  profile: {
    display_name: string | null;
    email: string | null;
    avatar_url: string | null;
  };
}

interface SearchResult {
  id: string;
  display_name: string | null;
  email: string | null;
  avatar_url: string | null;
}

interface Props {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  roomId: string;
  createdBy: string;
  currentUserId: string;
}

const WorkspaceMembersDialog = ({ open, onOpenChange, roomId, createdBy, currentUserId }: Props) => {
  const [members, setMembers] = useState<Member[]>([]);
  const [loadingMembers, setLoadingMembers] = useState(true);
  const [search, setSearch] = useState("");
  const [searchResults, setSearchResults] = useState<SearchResult[]>([]);
  const [searching, setSearching] = useState(false);
  const [addingId, setAddingId] = useState<string | null>(null);
  const [removingId, setRemovingId] = useState<string | null>(null);
  const [promotingId, setPromotingId] = useState<string | null>(null);
  const [generatingLink, setGeneratingLink] = useState(false);
  const [copiedLink, setCopiedLink] = useState(false);
  const [creatorPlan, setCreatorPlan] = useState<string | null>(null);
  const searchTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const isCreator = currentUserId === createdBy;

  const seatLimit = getSeatLimit(creatorPlan);
  const atSeatLimit = members.length >= seatLimit;

  useEffect(() => {
    if (open) {
      fetchMembers();
      fetchCreatorPlan();
      setSearch("");
      setSearchResults([]);
    }
  }, [open, roomId]);

  const fetchCreatorPlan = async () => {
    const { data } = await supabase
      .from("profiles")
      .select("subscription_plan")
      .eq("id", createdBy)
      .single();
    setCreatorPlan(data?.subscription_plan ?? "free");
  };

  const fetchMembers = async () => {
    setLoadingMembers(true);
    const { data } = await supabase
      .from("chat_room_members")
      .select("user_id, role")
      .eq("room_id", roomId);

    if (!data) { setLoadingMembers(false); return; }

    const profileIds = data.map((m) => m.user_id);
    const { data: profiles } = await supabase
      .from("profiles")
      .select("id, display_name, email, avatar_url")
      .in("id", profileIds);

    const profileMap = Object.fromEntries((profiles || []).map((p) => [p.id, p]));
    setMembers(
      data.map((m) => ({
        user_id: m.user_id,
        role: m.role,
        profile: profileMap[m.user_id] || { display_name: null, email: null, avatar_url: null },
      }))
    );
    setLoadingMembers(false);
  };

  const handleSearchChange = (value: string) => {
    setSearch(value);
    if (searchTimer.current) clearTimeout(searchTimer.current);
    if (!value.trim()) { setSearchResults([]); return; }

    searchTimer.current = setTimeout(async () => {
      setSearching(true);
      const excludeIds = [currentUserId, ...members.map((m) => m.user_id)];
      let query = supabase
        .from("profiles")
        .select("id, display_name, email, avatar_url")
        .or(`email.ilike.%${value}%,display_name.ilike.%${value}%`)
        .limit(6);

      if (excludeIds.length > 0) {
        query = query.not("id", "in", `(${excludeIds.join(",")})`);
      }

      const { data } = await query;
      setSearchResults(data || []);
      setSearching(false);
    }, 300);
  };

  const addMember = async (user: SearchResult) => {
    if (members.length >= seatLimit) {
      const planLabel = creatorPlan === "business" || creatorPlan === "brand_workspace" ? "Business" : "Pro";
      toast.error(`Seat limit reached (${seatLimit}/${seatLimit})`, {
        description: creatorPlan === "enterprise"
          ? "Contact support to increase your seat limit."
          : `Upgrade to ${planLabel === "Pro" ? "Business" : "Enterprise"} to add more seats.`,
      });
      return;
    }
    setAddingId(user.id);
    const { error } = await supabase
      .from("chat_room_members")
      .insert({ room_id: roomId, user_id: user.id, role: "member" });

    if (error) {
      toast.error("Failed to add member");
    } else {
      toast.success(`${user.display_name || user.email} added to workspace`);
      setSearchResults((prev) => prev.filter((r) => r.id !== user.id));
      setSearch("");
      fetchMembers();
    }
    setAddingId(null);
  };

  const removeMember = async (userId: string) => {
    setRemovingId(userId);
    const { error } = await supabase
      .from("chat_room_members")
      .delete()
      .eq("room_id", roomId)
      .eq("user_id", userId);

    if (error) {
      toast.error("Failed to remove member");
    } else {
      setMembers((prev) => prev.filter((m) => m.user_id !== userId));
      toast.success("Member removed");
    }
    setRemovingId(null);
  };

  const toggleRole = async (userId: string, currentRole: string) => {
    const isBusinessPlan = creatorPlan === "business" || creatorPlan === "brand_workspace" || creatorPlan === "enterprise";
    if (!isBusinessPlan) {
      toast.error("Business feature", { description: "Upgrade to Business to assign admin roles." });
      return;
    }
    setPromotingId(userId);
    const newRole = currentRole === "admin" ? "member" : "admin";
    const { error } = await supabase
      .from("chat_room_members")
      .update({ role: newRole })
      .eq("room_id", roomId)
      .eq("user_id", userId);
    if (error) {
      toast.error("Failed to update role");
    } else {
      setMembers((prev) =>
        prev.map((m) => m.user_id === userId ? { ...m, role: newRole } : m)
      );
      toast.success(newRole === "admin" ? "Promoted to admin" : "Demoted to member");
    }
    setPromotingId(null);
  };

  const generateInviteLink = async () => {
    if (members.length >= seatLimit) {
      toast.error(`Seat limit reached (${seatLimit}/${seatLimit})`, {
        description: "Remove a member or upgrade your plan to invite more people.",
      });
      return;
    }
    setGeneratingLink(true);
    try {
      const { data, error } = await supabase
        .from("workspace_invites" as any)
        .insert({ room_id: roomId, invited_by: currentUserId })
        .select("token")
        .single();
      if (error) throw error;
      const link = `${window.location.origin}/invite/${(data as any).token}`;
      await navigator.clipboard.writeText(link);
      setCopiedLink(true);
      setTimeout(() => setCopiedLink(false), 2500);
      toast.success("Invite link copied to clipboard");
    } catch {
      toast.error("Failed to generate invite link");
    } finally {
      setGeneratingLink(false);
    }
  };

  const getInitial = (profile: SearchResult | Member["profile"]) =>
    profile.display_name?.charAt(0) || profile.email?.charAt(0) || "?";

  const getName = (profile: SearchResult | Member["profile"]) =>
    profile.display_name || profile.email || "Unknown";

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Users className="w-4 h-4 text-bronze" />
            Workspace Members
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          {/* Invite link — creator only */}
          {isCreator && (
            <button
              onClick={generateInviteLink}
              disabled={generatingLink || atSeatLimit}
              className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl border border-dashed transition-all text-left group ${
                atSeatLimit
                  ? "border-muted-foreground/20 bg-muted/30 cursor-not-allowed opacity-60"
                  : "border-bronze/30 bg-bronze/5 hover:bg-bronze/10 hover:border-bronze/50"
              }`}
            >
              <div className={`w-7 h-7 rounded-lg flex items-center justify-center flex-shrink-0 ${atSeatLimit ? "bg-muted" : "bg-bronze/15"}`}>
                {atSeatLimit
                  ? <Lock className="w-3.5 h-3.5 text-muted-foreground" />
                  : <Link2 className="w-3.5 h-3.5 text-bronze" />
                }
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-xs font-semibold text-foreground">Share Invite Link</p>
                <p className="text-[10px] text-muted-foreground">
                  {atSeatLimit ? "Seat limit reached — upgrade to add more" : "Anyone with the link can join"}
                </p>
              </div>
              {generatingLink
                ? <Loader2 className="w-3.5 h-3.5 animate-spin text-bronze flex-shrink-0" />
                : copiedLink
                ? <Check className="w-3.5 h-3.5 text-emerald-500 flex-shrink-0" />
                : <Copy className={`w-3.5 h-3.5 flex-shrink-0 transition-colors ${atSeatLimit ? "text-muted-foreground/30" : "text-bronze/60 group-hover:text-bronze"}`} />
              }
            </button>
          )}

          {/* Search to add */}
          {isCreator && (
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
              <Input
                value={search}
                onChange={(e) => handleSearchChange(e.target.value)}
                placeholder="Search by email or name to add..."
                className="pl-9 pr-4"
              />
              {searching && (
                <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 animate-spin text-muted-foreground" />
              )}
            </div>
          )}

          {/* Search results */}
          {searchResults.length > 0 && (
            <div className="border border-border rounded-xl overflow-hidden divide-y divide-border">
              {searchResults.map((user) => (
                <div key={user.id} className="flex items-center gap-3 px-3 py-2.5 bg-muted/20">
                  <Avatar className="h-8 w-8 flex-shrink-0">
                    <AvatarImage src={user.avatar_url || undefined} />
                    <AvatarFallback className="text-xs bg-bronze/20 text-bronze">
                      {getInitial(user)}
                    </AvatarFallback>
                  </Avatar>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium truncate">{getName(user)}</p>
                    {user.display_name && (
                      <p className="text-xs text-muted-foreground truncate">{user.email}</p>
                    )}
                  </div>
                  <Button
                    size="sm"
                    onClick={() => addMember(user)}
                    disabled={addingId === user.id}
                    className="h-7 gap-1.5 bg-bronze hover:bg-bronze/90 text-background flex-shrink-0"
                  >
                    {addingId === user.id
                      ? <Loader2 className="w-3.5 h-3.5 animate-spin" />
                      : <UserPlus className="w-3.5 h-3.5" />}
                    Add
                  </Button>
                </div>
              ))}
            </div>
          )}

          {search && !searching && searchResults.length === 0 && (
            <p className="text-xs text-muted-foreground text-center py-2">No users found</p>
          )}

          {/* Current members */}
          <div>
            <div className="flex items-center justify-between mb-2">
              <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                Members · {members.length}
              </p>
              {seatLimit < 100 && (
                <span className={`text-[10px] font-semibold px-2 py-0.5 rounded-full ${
                  atSeatLimit
                    ? "bg-red-500/10 text-red-400"
                    : "bg-muted text-muted-foreground"
                }`}>
                  {members.length} / {seatLimit} seats
                </span>
              )}
            </div>
            {loadingMembers ? (
              <div className="space-y-2">
                {[...Array(2)].map((_, i) => (
                  <div key={i} className="h-12 rounded-xl bg-muted/50 animate-pulse" />
                ))}
              </div>
            ) : (
              <div className="space-y-1">
                {members.map((m) => (
                  <div key={m.user_id} className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-muted/30 transition-colors">
                    <Avatar className="h-8 w-8 flex-shrink-0">
                      <AvatarImage src={m.profile.avatar_url || undefined} />
                      <AvatarFallback className="text-xs bg-bronze/20 text-bronze">
                        {getInitial(m.profile)}
                      </AvatarFallback>
                    </Avatar>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1.5">
                        <p className="text-sm font-medium truncate">{getName(m.profile)}</p>
                        {m.user_id === createdBy && (
                          <Crown className="w-3 h-3 text-bronze flex-shrink-0" />
                        )}
                      </div>
                      {m.profile.display_name && (
                        <p className="text-xs text-muted-foreground truncate">{m.profile.email}</p>
                      )}
                    </div>
                    <Badge variant="outline" className="text-[10px] capitalize flex-shrink-0">
                      {m.user_id === createdBy ? "owner" : m.role}
                    </Badge>
                    {isCreator && m.user_id !== createdBy && (
                      <div className="flex items-center gap-1 flex-shrink-0">
                        <button
                          onClick={() => toggleRole(m.user_id, m.role)}
                          disabled={promotingId === m.user_id}
                          className="text-muted-foreground hover:text-bronze transition-colors"
                          aria-label={m.role === "admin" ? "Demote to member" : "Promote to admin (Business+)"}
                          title={m.role === "admin" ? "Demote to member" : "Promote to admin (Business plan required)"}
                        >
                          {promotingId === m.user_id
                            ? <Loader2 className="w-3.5 h-3.5 animate-spin" />
                            : m.role === "admin"
                            ? <ShieldOff className="w-3.5 h-3.5" />
                            : <ShieldCheck className="w-3.5 h-3.5" />}
                        </button>
                        <button
                          onClick={() => removeMember(m.user_id)}
                          disabled={removingId === m.user_id}
                          className="text-muted-foreground hover:text-destructive transition-colors"
                          aria-label="Remove member"
                        >
                          {removingId === m.user_id
                            ? <Loader2 className="w-3.5 h-3.5 animate-spin" />
                            : <X className="w-3.5 h-3.5" />}
                        </button>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default WorkspaceMembersDialog;

import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { motion } from "framer-motion";
import { Plus, MessageSquare, FileSignature, Receipt, ArrowRight, Sparkles, Users } from "lucide-react";
import { useSubscription } from "@/hooks/use-subscription";
import { toast } from "sonner";

const WorkspacesList = () => {
  const navigate = useNavigate();
  const [workspaces, setWorkspaces] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [userId, setUserId] = useState<string | null>(null);
  const { isFree, limits } = useSubscription();

  useEffect(() => { fetchWorkspaces(); }, []);

  const fetchWorkspaces = async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    setUserId(user.id);

    const { data } = await supabase
      .from("chat_rooms")
      .select("*, chat_room_members(user_id, role)")
      .order("updated_at", { ascending: false });

    setWorkspaces(data || []);
    setLoading(false);
  };

  const createWorkspace = async () => {
    if (!userId) return;

    if (isFree) {
      const ownedCount = workspaces.filter(w => w.created_by === userId).length;
      if (ownedCount >= limits.maxWorkspaces) {
        toast.error("Workspace limit reached", {
          description: "Free plan allows 1 workspace. Upgrade to Pro or Business for unlimited workspaces.",
        });
        return;
      }
    }

    const { data, error } = await supabase
      .from("chat_rooms")
      .insert({ created_by: userId, is_group: false, name: "New Workspace" })
      .select()
      .single();

    if (!error && data) {
      await supabase.from("chat_room_members").insert({ room_id: data.id, user_id: userId, role: "admin" });
      navigate(`/crevia-workspace/${data.id}`);
    }
  };

  return (
    <div className="min-h-screen bg-background">
      <div className="max-w-5xl mx-auto px-4 py-8 md:px-6 md:py-12">
        {/* Header */}
        <div className="flex items-center justify-between mb-8">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <Sparkles className="w-5 h-5 text-bronze" />
              <h1 className="font-vollkorn text-2xl md:text-3xl font-bold">Workspaces</h1>
            </div>
            <p className="text-muted-foreground text-sm">Your active deal rooms with clients and brands</p>
          </div>
          <Button onClick={createWorkspace} className="bg-bronze hover:bg-bronze/90 text-background gap-2">
            <Plus className="w-4 h-4" />
            New Workspace
          </Button>
        </div>

        {/* Workspaces Grid */}
        {loading ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {[...Array(4)].map((_, i) => (
              <div key={i} className="h-36 bg-muted/50 rounded-2xl animate-pulse" />
            ))}
          </div>
        ) : workspaces.length === 0 ? (
          <div className="text-center py-24">
            <div className="w-20 h-20 rounded-full bg-bronze/10 flex items-center justify-center mx-auto mb-4">
              <MessageSquare className="w-10 h-10 text-bronze/50" />
            </div>
            <h3 className="font-vollkorn text-xl font-bold mb-2">No workspaces yet</h3>
            <p className="text-muted-foreground text-sm mb-6 max-w-sm mx-auto">
              Create your first workspace to start collaborating with a client or brand in a professional deal room.
            </p>
            <Button onClick={createWorkspace} className="bg-bronze hover:bg-bronze/90 text-background gap-2">
              <Plus className="w-4 h-4" />
              Create First Workspace
            </Button>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {workspaces.map((workspace, idx) => (
              <motion.div
                key={workspace.id}
                initial={{ opacity: 0, y: 16 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.3, delay: idx * 0.05 }}
              >
                <Card
                  onClick={() => navigate(`/crevia-workspace/${workspace.id}`)}
                  className="p-5 cursor-pointer hover:border-bronze/40 hover:shadow-md transition-all group"
                >
                  <div className="flex items-start justify-between mb-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-xl bg-bronze/10 flex items-center justify-center">
                        <MessageSquare className="w-5 h-5 text-bronze" />
                      </div>
                      <div>
                        <h3 className="font-semibold text-sm">{workspace.name || "Workspace"}</h3>
                        <p className="text-[10px] text-muted-foreground">
                          {new Date(workspace.updated_at).toLocaleDateString()}
                        </p>
                      </div>
                    </div>
                    <Badge variant="outline" className="text-[10px] border-bronze/30 text-bronze">
                      Active
                    </Badge>
                  </div>

                  <div className="flex items-center gap-3 mb-4">
                    <div className="flex items-center gap-1.5 text-muted-foreground">
                      <Users className="w-3.5 h-3.5" />
                      <span className="text-xs">{workspace.chat_room_members?.length || 1} members</span>
                    </div>
                    <div className="flex items-center gap-1.5 text-muted-foreground">
                      <FileSignature className="w-3.5 h-3.5" />
                      <span className="text-xs">Canvas</span>
                    </div>
                    <div className="flex items-center gap-1.5 text-muted-foreground">
                      <Receipt className="w-3.5 h-3.5" />
                      <span className="text-xs">Invoice</span>
                    </div>
                  </div>

                  <div className="flex items-center justify-between">
                    <span className="text-xs text-muted-foreground">Click to open workspace</span>
                    <ArrowRight className="w-4 h-4 text-bronze opacity-0 group-hover:opacity-100 transition-opacity" />
                  </div>
                </Card>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default WorkspacesList;

